1. What is Sanity * ** # Sanity.io is the unified content platform that powers better digital experiences
 2. Sanity Project 만들고 Deploy 하기 #npm install -g @sanity/cli sanity login # Sanity 시작 sanity init # 로컬에서 서버 띄우기, query 직접 띄워보기 가능 sanity start # Sanity에서 서버 띄우기 sanity deploy 3. Schema (1) - author #// author.js export default { name: &#34;author&#34;, title: &#34;Author&#34;, type: &#34;document&#34;, fields: [ { name: &#34;name&#34;, title: &#34;Name&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;role&#34;, title: &#34;Role&#34;, type: &#34;string&#34;, }, { name: &#34;image&#34;, title: &#34;Image&#34;, type: &#34;image&#34;, options: { hotspot: true, }, validation: (Rule) =&gt; Rule.required(), }, ], preview: { select: { title: &#34;name&#34;, media: &#34;image&#34;, }, }, }; 4. Schema (2) - post #// post.js export default { name: &#34;post&#34;, title: &#34;Post&#34;, type: &#34;document&#34;, fields: [ { name: &#34;title&#34;, title: &#34;Title&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { // URL, Unique  name: &#34;slug&#34;, title: &#34;Slug&#34;, type: &#34;slug&#34;, options: { source: &#34;title&#34;, maxLength: 96, }, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;subtitle&#34;, title: &#34;Subtitle&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;author&#34;, title: &#34;Author&#34;, type: &#34;reference&#34;, to: { type: &#34;author&#34; }, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;content&#34;, title: &#34;Content&#34;, type: &#34;blockContent&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;createdAt&#34;, title: &#34;Created at&#34;, type: &#34;datetime&#34;, }, { name: &#34;thumbnail&#34;, title: &#34;Thumbnail&#34;, type: &#34;image&#34;, options: { hotspot: true, }, fields: [ { name: &#34;alt&#34;, title: &#34;alt&#34;, type: &#34;string&#34;, options: { isHighlighted: true, }, validation: (Rule) =&gt; Rule.required(), }, ], validation: (Rule) =&gt; Rule.required(), }, { name: &#34;category&#34;, title: &#34;Category&#34;, type: &#34;reference&#34;, to: { type: &#34;category&#34; }, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;tag&#34;, title: &#34;Tag&#34;, type: &#34;array&#34;, of: [{ type: &#34;reference&#34;, to: { type: &#34;tag&#34; } }], }, ], preview: { select: { title: &#34;title&#34;, author: &#34;author.name&#34;, media: &#34;thumbnail&#34;, }, prepare(selection) { const { author } = selection; return Object.assign({}, selection, { subtitle: author &amp;&amp; `by ${author}`, }); }, }, }; // category.js export default { name: &#34;category&#34;, title: &#34;Category&#34;, type: &#34;document&#34;, fields: [ { name: &#34;title&#34;, title: &#34;Title&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;slug&#34;, title: &#34;Slug&#34;, type: &#34;slug&#34;, options: { source: &#34;title&#34;, maxLength: 96, }, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;description&#34;, title: &#34;Description&#34;, type: &#34;text&#34;, }, ], preview: { select: { title: &#34;title&#34;, subtitle: &#34;description&#34;, }, }, }; // tag.js export default { name: &#34;tag&#34;, title: &#34;Tag&#34;, type: &#34;document&#34;, fields: [ { name: &#34;title&#34;, title: &#34;Title&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;slug&#34;, title: &#34;Slug&#34;, type: &#34;slug&#34;, options: { source: &#34;title&#34;, maxLength: 96, }, validation: (Rule) =&gt; Rule.required(), }, ], preview: { select: { title: &#34;title&#34;, subtitle: &#34;slug.current&#34;, }, }, }; 5. Schema (3) - home #// home.js export default { name: &#34;home&#34;, title: &#34;Home&#34;, type: &#34;document&#34;, fields: [ { name: &#34;title&#34;, title: &#34;Title&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;mainPost&#34;, title: &#34;Main Post&#34;, type: &#34;reference&#34;, to: { type: &#34;post&#34; }, validation: (Rule) =&gt; Rule.required(), }, ], preview: { select: { title: &#34;title&#34;, subtitle: &#34;mainPost.title&#34;, media: &#34;mainPost.thumbnail&#34;, }, }, }; 6. Schema (4) - blockContent #// blockContent.js /** * This is the schema definition for the rich text fields used for * for this blog studio. When you import it in schemas.js it can be * reused in other parts of the studio with: * { * name: &#39;someName&#39;, * title: &#39;Some title&#39;, * type: &#39;blockContent&#39; * } */ export default { title: &#34;Block Content&#34;, name: &#34;blockContent&#34;, type: &#34;array&#34;, of: [ { title: &#34;Block&#34;, type: &#34;block&#34;, // Styles let you set what your user can mark up blocks with. These  // correspond with HTML tags, but you can set any title or value  // you want and decide how you want to deal with it where you want to  // use your content.  styles: [ { title: &#34;Normal&#34;, value: &#34;normal&#34; }, { title: &#34;H1&#34;, value: &#34;h1&#34; }, { title: &#34;H2&#34;, value: &#34;h2&#34; }, { title: &#34;H3&#34;, value: &#34;h3&#34; }, { title: &#34;H4&#34;, value: &#34;h4&#34; }, { title: &#34;H5&#34;, value: &#34;h5&#34; }, { title: &#34;Quote&#34;, value: &#34;blockquote&#34; }, ], lists: [ { title: &#34;Bullet&#34;, value: &#34;bullet&#34; }, { title: &#34;Numbered&#34;, value: &#34;number&#34; }, ], // Marks let you mark up inline text in the block editor.  marks: { // Decorators usually describe a single property – e.g. a typographic  // preference or highlighting by editors.  decorators: [ { title: &#34;Strong&#34;, value: &#34;strong&#34; }, { title: &#34;Emphasis&#34;, value: &#34;em&#34; }, ], // Annotations can be any object structure – e.g. a link or a footnote.  annotations: [ { title: &#34;URL&#34;, name: &#34;link&#34;, type: &#34;object&#34;, fields: [ { title: &#34;URL&#34;, name: &#34;href&#34;, type: &#34;url&#34;, }, ], }, ], }, }, // You can add additional types here. Note that you can&#39;t use  // primitive types such as &#39;string&#39; and &#39;number&#39; in the same array  // as a block type.  { type: &#34;image&#34;, options: { hotspot: true }, fields: [ { name: &#34;caption&#34;, title: &#34;Caption&#34;, type: &#34;string&#34;, option: { isHighlighted: true, }, }, { name: &#34;alt&#34;, title: &#34;Alt&#34;, type: &#34;string&#34;, option: { isHighlighted: true, }, validation: (Rule) =&gt; Rule.required(), }, ], }, { type: &#34;video&#34;, }, { type: &#34;code&#34;, }, { type: &#34;link&#34;, }, { type: &#34;imageGallery&#34;, }, ], }; // video.js export default { name: &#34;video&#34;, title: &#34;Video&#34;, type: &#34;object&#34;, fields: [ { name: &#34;caption&#34;, title: &#34;caption&#34;, type: &#34;string&#34;, }, { name: &#34;metadata&#34;, title: &#34;Metadata&#34;, type: &#34;urlWithMetadata&#34;, }, ], preview: { select: { title: &#34;caption&#34;, subtitle: &#34;metadata.url&#34;, }, }, }; * https://www.sanity.io/plugins/sanity-plugin-url-metadata-input
// code.js export default { name: &#34;code&#34;, title: &#34;Code&#34;, type: &#34;object&#34;, fields: [ { name: &#34;title&#34;, title: &#34;Title&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;language&#34;, title: &#34;Language&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;code&#34;, title: &#34;Code&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, ], }; // link.js export default { name: &#34;link&#34;, title: &#34;Link&#34;, type: &#34;object&#34;, fields: [ { name: &#34;metadata&#34;, title: &#34;Metadata&#34;, type: &#34;urlWithMetadata&#34;, }, ], preview: { select: { title: &#34;metadata.openGraph.title&#34;, subtitle: &#34;metadata.openGraph.url&#34;, }, }, }; // imageGallery.js export default { name: &#34;imageGallery&#34;, title: &#34;Image Gallery&#34;, type: &#34;object&#34;, fields: [ { name: &#34;caption&#34;, title: &#34;Caption&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;images&#34;, title: &#34;Images&#34;, type: &#34;array&#34;, options: { layout: &#34;grid&#34;, }, of: [ { name: &#34;image&#34;, title: &#34;Image&#34;, type: &#34;image&#34;, hotspot: true, fields: [ { name: &#34;alt&#34;, title: &#34;Alt&#34;, type: &#34;string&#34;, option: { isHighlighted: true, }, validation: (Rule) =&gt; Rule.required(), }, ], validation: (Rule) =&gt; Rule.required(), }, ], validation: (Rule) =&gt; Rule.required().max(4), }, ], }; 7. Studio의 input 커스터마이징 * #npm i yarn -g yarn add react-ace // components/CodeInput.jsx import React, { useCallback } from &#34;react&#34;; // import { Stack, Label, TextInput } from &#34;@sanity/ui&#34;; import { FormField } from &#34;@sanity/base/components&#34;; import AceEditor from &#34;react-ace&#34;; import &#34;ace-builds/src-noconflict/theme-chrome&#34;; import &#34;ace-builds/src-noconflict/mode-javascript&#34;; import PatchEvent, { set, unset } from &#34;@sanity/form-builder/PatchEvent&#34;; const CodeInput = React.forwardRef((props, ref) =&gt; { const { type, // Schema information  value, // Current field value  readOnly, // Boolean if field is not editable  placeholder, // Placeholder text from the schema  markers, // Markers including validation rules  presence, // Presence information for collaborative avatars  compareValue, // Value to check for &#34;edited&#34; functionality  onFocus, // Method to handle focus state  onBlur, // Method to handle blur state  onChange, } = props; const codeChange = useCallback( (code) =&gt; { onChange(PatchEvent.from(code ? set(code) : unset())); }, [onChange] ); return ( &lt;FormField description={type.description} // Creates description from schema  title={type.title} // Creates label from schema title  __unstable_markers={markers} // Handles all markers including validation  __unstable_presence={presence} // Handles presence avatars  compareValue={compareValue} // Handles &#34;edited&#34; status  &gt; &lt;AceEditor ref={ref} value={value} tabSize={2} setOptions={{ useWorker: false }} onChange={codeChange} mode=&#34;javascript&#34; name=&#34;ace-editor-code&#34; width=&#34;100%&#34; theme=&#34;chrome&#34; style={{ boxShadow: &#34;0 0 0 1px #cad1dc&#34;, lineHeight: 1.6, }} /&gt; &lt;/FormField&gt; ); }); export default CodeInput; import CodeInput from &#34;../components/CodeInput&#34;; export default { name: &#34;code&#34;, title: &#34;Code&#34;, type: &#34;object&#34;, fields: [ { name: &#34;title&#34;, title: &#34;Title&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;language&#34;, title: &#34;Language&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), }, { name: &#34;code&#34;, title: &#34;Code&#34;, type: &#34;string&#34;, validation: (Rule) =&gt; Rule.required(), inputComponent: CodeInput, }, ], }; 8. Query #*[_type == 'home'][0]{'mainPostURL': mainPost -&gt; slug.current}*[_type == 'post']{title,subtitle,createdAt,&quot;content&quot;: content[]{...,...select(_type == &quot;imageGallery&quot; =&gt; {&quot;images&quot;: images[]{..., &quot;url&quot;: asset -&gt; url}})},&quot;slug&quot;: slug.current,&quot;thumbnail&quot;: {&quot;alt&quot;: thumbnail.alt,&quot;imageUrl&quot;: thumbnail.asset -&gt; url},&quot;author&quot;: author -&gt; {name,role,&quot;image&quot;: image.asset -&gt; url},&quot;category&quot;: category -&gt; {title,&quot;slug&quot;: slug.current}}

1. Instagram Schema Design # https://dbdiagram.io/home  2. 데이터베이스 연결과 스키마 #.env # .gitignore 필요  DATABASE_USERNAME=&#39;root&#39; DATABASE_PASSWORD=&#39;1234&#39; DATABASE_NAME=&#39;mylearnsql&#39; Dotenv #const dotenv = require(&#39;dotenv&#39;); const mysql = require(&#39;mysql&#39;); ... constructor() { super(); this.config = { host: &#39;localhost&#39;, user: process.env.DATABASE_USERNAME || &#39;root&#39;, password: process.env.DATABASE_PASSWORD || &#39;&#39;, database: process.env.DATABASE_NAME || &#39;learnmysql&#39; }; init() { this.connection = mysql.createConnection({ ...this.config, multipleStatements: true }); ... schema.sql #USElearnmysql;CREATETABLE`user`(`id`intPRIMARYKEYAUTO_INCREMENT,`name`varchar(255)notNULL,`email`varchar(255)notNULL);CREATETABLE`content`(`id`intPRIMARYKEYAUTO_INCREMENT,`title`varchar(255)notNULL,`body`varchar(255)notNULL,`created_at`timestampnotNULLDEFAULTCURRENT_TIMESTAMP,`userId`int,FOREIGNKEY(`userId`)REFERENCES`user`(`id`));Script #// 현재 있는 데이터베이스에 존재하는 모든 테이블 정보를 보기위한 SQL을 작성해주세요. const PART3_1 = `show tables`; // user 테이블의 구조를 보기위한 SQL을 작성해주세요. const PART3_2 = `DESC user`; // content 테이블의 구조를 보기위한 SQL을 작성해주세요. const PART3_3 = `DESC content`; + Redux with FastCampus #1. Redux 개요 # Single Store  [만들기] 단일 스토어 사용 준비  import redux Action을 정의하고, Action을 사용하는, Reducer를 만들고, Reducer들을 합침 최종 합쳐진 Reducer를 인자로, Single Store를 만듦   [사용하기] 준비한 스토어를 리액트 컴포넌트에서 사용  import react-redux connect 함수를 이용해서 컴포넌트에 연결     npm i redux  1) Actions #  Action of Redux
 액션은 사실 그냥 객체(object) 두 가지 형태의 액션  payload 없는 액션  { type: &lsquo;TEST&rsquo; }   payload 있는 액션  { type: &lsquo;TEST&rsquo;, params: &lsquo;hello&rsquo; }     type만이 필수 프로퍼티이며, type은 문자열    Action Creator of Redux
 함수를 통해 액션을 생성해서, 액션 객체를 리턴 function 액션생성자(...arg) { return 액션; }     Redux에서 Action의 역할
 액션 생성자를 통해 액션을 만듦 만든 액션 객체를 리덕스 스토어로 보냄 리덕스 그토어가 액션 객체를 받으면 스토어의 상태 값이 변경 변경된 상태값에 의해 해당 상태를 이용하고 있는 컴포넌트가 변경    Action 준비
 액션의 타입을 정의하여 변수로 빼는 단계  강제는 아닙니다. (그러므로 안해도 됩니다.) 그냥 타입을 문자열로 넣기에는 실수를 유발할 가능성이 큽니다. 미리 정의한 변수를 사용하면, 스펠링에 주의를 덜 기울여도 됩니다.   액션 객체를 만들어 내는 함수를 만드는 단계  하나의 액션 객체를 만들기 위해 하나의 함수를 만들어냅니다. 액션의 타입은 미리 정의한 타입 변수로 부터 가져와서 사용합니다.      /* actions.js */ // 1) 액션의 type 정의 // 액션의 타입 =&gt; 액션 생성자 이름 // ADD_TODO =&gt; addTodo export const ADD_TODO = &#34;ADD_TODO&#34;; export const COMPLETE_TODO = &#34;COMPLETE_TODO&#34;; export const SHOW_ALL = &#34;SHOW_ALL&#34;; export const SHOW_COMPLETE = &#34;SHOW_COMPLETE&#34;; // 2) 액션 생산자 // 액션의 타입은 미리 정의한 타입으로 부터 가져와서 사용하며, // 사용자가 인자로 주지 않습니다. export function addTodo(text) { return { type: ADD_TODO, text }; // { type: ADD_TODO, text: &#34;todo&#34; } } export function completeTodo(index) { return { type: COMPLETE_TODO, index }; // { type: COMPLETE_TODO, index: num } } export function showAll() { return { type: SHOW_ALL }; // { type: SHOW_ALL } } export function showComplete() { return { type: SHOW_COMPLETE }; // { type: SHOW_COMPLETE } } 2) Reducers # 액션을 주면, 그 액션이 적용된 결과를 만듦 Pure Function  시간에 따라 달라지는 결과를 가지는 등의 코드는 들어가면 안됨   Immutable  원래 state와 바뀐 state가 별도로 만들어 져야함 리듀서를 통해 스테이트가 달라졌음을 리덕스가 인지하는 방식이라서  function 리듀서(previousState, action) { return newState; }  액션을 받아서 스테이트를 리턴하는 구조 인자로 들어오는 previousState 와 리턴되는 newState 는 다른 참조를 가지도록 해야함(immutable)    /* reducers.js */ import { ADD_TODO, COMPLETE_TODO, SHOW_ALL, SHOW_COMPLETE } from &#34;./actions&#34;; const initState = { todos: [], filter: &#34;ALL&#34; }; export function todoApp(prevState = initState, action) { if (action.type === ADD_TODO) { return { ...prevState, todos: [...prevState.todos, { text: action.text, completed: false }], }; } if (action.type === COMPLETE_TODO) { return { ...prevState, todos: prevState.todos.map((todo, index) =&gt; { if (index === action.index) { return { ...todo, completed: true }; } return todo; }), }; } if (action.type === SHOW_COMPLETE) { return { ...prevState, filter: &#34;COMPLETE&#34;, }; } if (action.type === SHOW_ALL) { return { ...prevState, filter: &#34;ALL&#34;, }; } return prevState; } 3) createStore &amp; dispatch &amp; subscribe #/* store.js */ import { todoApp } from &#34;./reducers&#34;; import { createStore } from &#34;redux&#34;; import { addTodo, completeTodo } from &#34;./actions&#34;; const store = createStore(todoApp); setTimeout(() =&gt; { store.dispatch(addTodo(&#34;hello&#34;)); setTimeout(() =&gt; { store.dispatch(completeTodo(0)); }, 1000); }, 1000); export default store; /* index.js */ ... import store from &#34;./redux/store&#34;; import { addTodo, completeTodo, showAll, showComplete } from &#34;./redux/actions&#34;; /* const unsubscribe = store.subscribe(() =&gt; { console.log(store.getState()); }); store.dispatch(addTodo(&#34;코딩&#34;)); store.dispatch(addTodo(&#34;운동&#34;)); store.dispatch(addTodo(&#34;독서&#34;)); unsubscribe(); store.dispatch(addTodo(&#34;코딩&#34;)); store.dispatch(addTodo(&#34;운동&#34;)); store.dispatch(addTodo(&#34;독서&#34;)); console.log(store.getState()); */ store.subscribe(() =&gt; { console.log(store.getState()); }); store.dispatch(addTodo(&#34;할일&#34;)); // {todos: [{text: &#34;할일&#34;, completed: false}], filter: &#34;ALL&#34;} store.dispatch(completeTodo(0)); // {todos: [{text: &#34;할일&#34;, completed: true}], filter: &#34;ALL&#34;} store.dispatch(showComplete()); // {todos: [{text: &#34;할일&#34;, completed: true}], filter: &#34;COMPLETE&#34;} store.dispatch(showAll()); // {todos: [{text: &#34;할일&#34;, completed: true}], filter: &#34;ALL&#34;} ...  store.getState() store.dispatch(액션);
store.dispatch(액션생성자()); const unsubscribe = store.subscribe(() =&gt; {});  리턴이 unsubscribe 즉, unsubscribe(); 하면 제거    2. combineReducers #1) action.js #// action.js  // 1) 액션의 type 정의 export const ADD_TODO = &#34;ADD_TODO&#34;; export const COMPLETE_TODO = &#34;COMPLETE_TODO&#34;; export const SHOW_ALL = &#34;SHOW_ALL&#34;; export const SHOW_COMPLETE = &#34;SHOW_COMPLETE&#34;; // 2) 액션 생산자 export function addTodo(text) { return { type: ADD_TODO, text }; // { type: ADD_TODO, text: &#34;todo&#34; } } export function completeTodo(index) { return { type: COMPLETE_TODO, index }; // { type: COMPLETE_TODO, index: num } } export function showAll() { return { type: SHOW_ALL }; // { type: SHOW_ALL } } export function showComplete() { return { type: SHOW_COMPLETE }; // { type: SHOW_COMPLETE } } 2) reducers #// reducers/reducer.js // combineReducers  import { combineReducers } from &#34;redux&#34;; import todos from &#34;./todos&#34;; import filter from &#34;./filter&#34;; const reducer = combineReducers({ todos: todos, filter: filter, }); export default reducer; // reducers/todos.js  import { ADD_TODO, COMPLETE_TODO } from &#34;../actions&#34;; const initState = []; export default function todos(prevState = initState, action) { if (action.type === ADD_TODO) { return [...prevState, { text: action.text, completed: false }]; } if (action.type === COMPLETE_TODO) { return prevState.map((todo, index) =&gt; { if (index === action.index) { return { ...todo, completed: true }; } return todo; }); } return prevState; } // reducers/filter.js  import { SHOW_ALL, SHOW_COMPLETE } from &#34;../actions&#34;; const initState = &#34;ALL&#34;; export default function filter(prevState = initState, action) { if (action.type === SHOW_COMPLETE) { return &#34;COMPLETE&#34;; } if (action.type === SHOW_ALL) { return &#34;ALL&#34;; } return prevState; } 3) store.js #/* store.js */ import reducer from &#34;./reducers/reducer&#34;; import { createStore } from &#34;redux&#34;; const store = createStore(reducer); export default store; 3. React-Redux # index.js App.js /redux  actions.js /reducer  reducer.js /reducers  todos.js filter.js     store.js   /components  TodoList.jsx TodoForm.jsx   /containers  TodoListContainer.jsx TodoFormContainer.jsx    A. Redux #1) actions.js #// redux/actions.js // 1) 액션 Type export const ADD_TODO = &#34;ADD_TODO&#34;; export const COMPLETE_TODO = &#34;COMPLETE_TODO&#34;; export const SHOW_ALL = &#34;SHOW_ALL&#34;; export const SHOW_COMPLETE = &#34;SHOW_COMPLETE&#34;; // 2) 액션 생성자 export function addTodo(text) { return { type: ADD_TODO, text }; // { type: ADD_TODO, text: &#34;todo&#34; } } export function completeTodo(index) { return { type: COMPLETE_TODO, index }; // { type: COMPLETE_TODO, index: num } } export function showAll() { return { type: SHOW_ALL }; // { type: SHOW_ALL } } export function showComplete() { return { type: SHOW_COMPLETE }; // { type: SHOW_COMPLETE } } 2) /reducer #  combineReducers()
