Intro to Algorithm # 알고리즘이란 문제를 해결하는 최선의 선택   문제 이해 해결 전략 구상(with 수도 코드) 수도 코드를 바탕으로 코드 작성  1. Time Complexity #시간 복잡도 # 입력값의 변화에 따라 연산을 실행할 때, 연산 횟수에 비해 시간이 얼마만큼 걸리는가? Big-O는 상한, Big-Θ(theta)는 평균, Big-Ω(omega)는 하한  Big-O 표기법 # 프로그램이 실행되는 과정에서 소요되는 최악의 시간까지 고려    O(1)
 constant complexity 입력값이 증가하더라도 시간이 늘어나지 않음  function O_1_algorithm(arr, index) { return arr[index]; } let arr = [1, 2, 3, 4, 5]; let index = 1; let result = O_1_algorithm(arr, index); console.log(result); // 2   O(n)
 linear complexity 입력값이 증가함에 따라 시간 또한 같은 비율로 증가 Ex. DFS(재귀 함수)  function O_n_algorithm(n) { for (let i = 0; i &lt; n; i++) { // do something for 1 second  } } function another_O_n_algorithm(n) { for (let i = 0; i &lt; 2n; i++) { // do something for 1 second  } }  n이 커질 수록 계수의 영향력이 퇴색되서 O(kn)도 모두 O(n)    O(log n)
 logarithmic complexity O(1) 다음으로 빠른 시간 복잡도 Ex. BFS(Queue)    O(n^2)
 quadratic complexity 입력값이 증가함에 따라 시간이 n의 제곱수의 비율로 증가  function O_quadratic_algorithm(n) { for (let i = 0; i &lt; n; i++) { for (let j = 0; j &lt; n; j++) { // do something for 1 second  } } } function another_O_quadratic_algorithm(n) { for (let i = 0; i &lt; n; i++) { for (let j = 0; j &lt; n; j++) { for (let k = 0; k &lt; n; k++) { // do something for 1 second  } } } }  n이 커질 수록 지수의 영향력이 퇴색되서 O(n^k)도 모두 O(n^2)    O(2^n)
 exponential complexity Big-O 표기법 중 가장 느린 시간 복잡도  function fibonacci(n) { if (n &lt;= 1) { return 1; } return fibonacci(n - 1) + fibonacci(n - 2); }    대략적인 데이터 크기에 따른 시간 복잡도    데이터 크기 제한 예상되는 시간 복잡도 사용 알고리즘     n ≤ 1,000,000 O(n) or O (log n) DFS(재귀함수) or BFS(Queue)   n ≤ 10,000 O(n2) 2중 반복문   n ≤ 500 O(n3) 3중 반복문      2-1. Greedy Algorithm # 선택의 순간마다 당장 눈앞에 보이는 최적의 상황만을 쫓아 최종적인 해답에 도달하는 방법   선택 절차(Selection Procedure)  현재 상태에서의 최적의 해답을 선택합니다.   적절성 검사(Feasibility Check)  선택된 해가 문제의 조건을 만족하는지 검사합니다.   해답 검사(Solution Check)  원래의 문제가 해결되었는지 검사하고, 해결되지 않았다면 선택 절차로 돌아가 위의 과정을 반복합니다      Ex.
 선택 절차  거스름돈의 동전 개수를 줄이기 위해 현재 가장 가치가 높은 동전을 우선 선택합니다.   적절성 검사  1번 과정을 통해 선택된 동전들의 합이 거슬러 줄 금액을 초과하는지 검사합니다. 초과하면 가장 마지막에 선택한 동전을 삭제하고, 1번으로 돌아가 한 단계 작은 동전을 선택합니다.   해답 검사  선택된 동전들의 합이 거슬러 줄 금액과 일치하는지 검사합니다. 액수가 부족하면 1번 과정부터 다시 반복합니다.      항상 최적의 결과를 보장하지는 못함(Ex. 도둑질)
But, 어느 정도 최적에 근사한 값을 빠르게 도출할 수 있는 장점이 있음
  탐욕 알고리즘을 적용하려면 해결하려는 문제가 다음의 2가지 조건을 성립하여야 함
 탐욕적 선택 속성(Greedy Choice Property)  앞의 선택이 이후의 선택에 영향을 주지 않습니다.   최적 부분 구조(Optimal Substructure)  문제에 대한 최종 해결 방법은 부분 문제에 대한 최적 문제 해결 방법으로 구성됩니다.      완전 탐색 # 문제를 무조건 해결할 수 있는 장점이 있으나, 효율적으로 동작하지 못할 가능성이 높음 Ex. Brute Force(무차별 대입, 조건/반복을 사용하여 해결), 재귀, 순열, DFS/BFS 등  시뮬레이션 # 모든 과정과 조건이 제시되어, 그 과정을 거친 결과가 무엇인지 확인하는 유형 문제 해결을 떠올리는 것 자체는 쉬울 수 있으나 길고 자세하여 코드로 옮기는 작업이 까다로울 수 있음  2-2. Dynamic Programming # 모든 경우의 수를 조합해 최적의 해법을 찾는 방식 주어진 문제를 여러 개의 하위 문제로 나누어 풀고, 하위 문제들의 해결 방법을 결합하여 최종 문제를 해결하는 문제 해결 방식 동적 프로그래밍을 적용하려면 해결하려는 문제가 다음의 2가지 조건을 성립하여야 함  큰 문제를 작은 문제로 나눌 수 있고, 이 작은 문제가 중복해서 발견된다. (Overlapping Sub-problems) 작은 문제에서 구한 정답은 그것을 포함하는 큰 문제에서도 같다. 즉, 작은 문제에서 구한 정답을 큰 문제에서도 사용할 수 있다. (Optimal Substructure)   주어진 문제를 단순히 반복 계산하여 해결하는 것이 아니라, 작은 문제의 결과가 큰 문제를 해결하는 데에 여러 번 사용될 수 있어야 합니다.(Ex. 효율적인 피보나치)    Recursion + Memoization (재귀) # Top-down 방식 시간과 메모리 사용량을 줄일 수 있음  function fibMemo(n, memo = []) { // 이미 해결한 하위 문제인지 찾아본다  if (memo[n] !== undefined) return memo[n]; if (n &lt;= 2) return 1; // 없다면 재귀로 결괏값을 도출하여 res 에 할당  let res = fibMemo(n - 1, memo) + fibMemo(n - 2, memo); // 추후 동일한 문제를 만났을 때 사용하기 위해 리턴 전에 memo 에 저장  memo[n] = res; return res; } Iteration + Tabulation (반복) # Bottom-up 방식  function fibTab(n) { if (n &lt;= 2) return 1; let fibNum = [0, 1, 1]; // n 이 1 &amp; 2일 때의 값을 미리 배열에 저장해 놓는다  for (let i = 3; i &lt;= n; i++) { fibNum[i] = fibNum[i - 1] + fibNum[i - 2]; // n &gt;= 3 부터는 앞서 배열에 저장해 놓은 값들을 이용하여  // n번째 피보나치 수를 구한 뒤 배열에 저장 후 리턴한다  } return fibNum[n]; } PS. 개발자 도구에서 함수 실행 시간 측정 방법 #var t0 = performance.now(); func(50); var t1 = performance.now(); console.log(&#34;runtime: &#34; + (t1 - t0) + &#34;ms&#34;); 문제 #1) Greedy(1) # 모든 짐을 옮기기 위해 필요한 박스(최대 두 개, 제한 무게 이하) 개수의 최솟값을 숫자로 반환  function movingStuff(stuff, limit) { let count = 0; stuff.sort((a, b) =&gt; a - b); let left = 0; let right = stuff.length - 1; while (left &lt;= right) { if (stuff[left] + stuff[right] &lt;= limit) { left++; right--; count++; } else { right--; count++; } } return count; } 2) Greedy(2) # 거스름돈을 만드는데 필요한 동전 개수의 최솟값  function partTimeJob(k) { let coins = [500, 100, 50, 10, 5, 1]; let count = 0; let remainder = k; for (let coin of coins) { let quotient = Math.floor(remainder / coin); count += quotient; remainder = remainder % coin; } return count; } 3) Simulation #function boardGame(board, operation) { let point = 0; let row = 0; let col = 0; const directions = operation.split(&#34;&#34;); const len = board.length; for (let direction of directions) { if (direction === &#34;U&#34;) row -= 1; if (direction === &#34;D&#34;) row += 1; if (direction === &#34;L&#34;) col -= 1; if (direction === &#34;R&#34;) col += 1; if (row &lt; 0 || col &lt; 0 || len &lt; row || len &lt; col) { return &#34;OUT&#34;; } point += board[row][col]; } return point; } // LOOK UP TABLE을 사용한다면 조건문을 추상화 function boardGame(board, operation) { const DIR = { U: [-1, 0], D: [1, 0], L: [0, -1], R: [0, 1], }; const len = board.length; const isValid = (row, col) =&gt; 0 &lt;= row &amp;&amp; row &lt; len &amp;&amp; 0 &lt;= col &amp;&amp; col &lt; len; let row = 0; let col = 0; let score = 0; for (let i = 0; i &lt; operation.length; i++) { const [dRow, dCol] = DIR[operation[i]]; row += dRow; col += dCol; if (!isValid(row, col)) return &#34;OUT&#34;; score += board[row][col]; } return score; } 4) Dynamic Programming, Bottom-up 방식 #function ocean(target, type) { // 0을 만드는 방법은 1가지(초기값)  const memo = [1].concat(Array(target).fill(0)); // 각 화폐 탐색  for (let currency of type) { // 해당 화폐로 j를 만들 수 있는 경우의 수를 memo에 저장  for (let j = 1; j &lt;= target; j++) { // 기존 경우의 수에 현재 화폐를 뺀 금액을 만들 수 있는 경우의 수(+1)를 더해준다  if (currency &lt;= j) memo[j] += memo[j - currency]; } } return memo[target]; }  Ex.    cur 0 20 30 40 50     10 1 1 1 1 1   20 - 2 2 3 3   50 - - - - 4     10으로 10 만들고, 10과 10으로 20 만들고, 10과 10과 10으로 30을 만들고, &hellip; 20으로 20 만들고, 10과 10으로 20 만들고, &hellip;    + React with FastCampus Project #프로젝트 개요 # Context API 와 Hooks 를 이용한 전역 상태 관리  ERROR #node:internal/modules/cjs/loader:48