t user1Path = path.join(__dirname, &#34;files/user1.json&#34;); const user2Path = path.join(__dirname, &#34;files/user2.json&#34;); const readAllUsers = () =&gt; { let promise1 = getDataFromFilePromise(user1Path); let promise2 = getDataFromFilePromise(user2Path); return Promise.all([promise1, promise2]) .then((dataSet) =&gt; `[${dataSet[0]}, ${dataSet[1]}]`) .then((text) =&gt; JSON.parse(text)); }; readAllUsers(); 05_async &amp; await #const path = require(&#34;path&#34;); const { getDataFromFilePromise } = require(&#34;./02_promiseConstructor&#34;); const user1Path = path.join(__dirname, &#34;files/user1.json&#34;); const user2Path = path.join(__dirname, &#34;files/user2.json&#34;); const readAllUsersAsyncAwait = async () =&gt; { let promise1 = await getDataFromFilePromise(user1Path); let promise2 = await getDataFromFilePromise(user2Path); /* 1 */ const text = `[${promise1}, ${promise2}]`; return JSON.parse(text); /* 2 */ const result = []; const obj1 = JSON.parse(promise1); const obj2 = JSON.parse(promise2); result.push(obj1, obj2); return result; }; readAllUsersAsyncAwait(); Today&rsquo;s takeaway # 하루 종일 풀어도 토이 프로젝트를 풀 수 없었다. Call Stack -&gt; Web AIP -&gt; Callback Queue -event loop-&gt; Call Stack 비동기로 처리되는 블로킹 함수의 실행 위치를 보장하기 위해 Callback, Promise(.then() &amp; .catch(), async &amp; await) 사용 Promise가 fulfilled되면 resole()의 인수를 return, rejected되면 reject()의 인수를 반환 Promise 생성자로 Promise(로 감싼 함수)를 생성 Promise에 .then()과 .catch()를 연결해서 실행 위치 보장 Promise 다음의 .then()의 인수는 resolve()의 인수고, .then() 다음의 인수는 .then()의 return 값 async 키워드로 Promise를 반환하는 함수로 만들고, await 키워드로 각 Promise들의 실행 위치 보장 Promise를 반환하는 함수들을 Promise.all()로 배열(dataSet)로써 한 번에 다룰 수 있다.

